#include <iostream>
#include <string>

int add(int a, int b) { return a + b; }
int subtract(int a, int b) { return a - b; }
int multiply(int a, int b) { return a * b; }

int main() {
    std::string op;
    int a, b;
    std::cin >> op >> a >> b;

    int (*fn)(int, int) = nullptr;
    if (op == "add")      fn = add;
    else if (op == "subtract") fn = subtract;
    else if (op == "multiply") fn = multiply;

    std::cout << fn(a, b) << "\n";
    return 0;
}

