#include <iostream>
#include <string>

bool ascending(int a, int b)  { return a < b; }
bool descending(int a, int b) { return a > b; }

void sortThree(int& a, int& b, int& c, bool (*cmp)(int, int)) {
    if (!cmp(a, b)) { int t = a; a = b; b = t; }
    if (!cmp(b, c)) { int t = b; b = c; c = t; }
    if (!cmp(a, b)) { int t = a; a = b; b = t; }
}

int main() {
    std::string order;
    int x, y, z;
    std::cin >> order >> x >> y >> z;

    bool (*cmp)(int, int) = ascending;
    if (order == "desc") cmp = descending;

    sortThree(x, y, z, cmp);
    std::cout << x << " " << y << " " << z << "\n";
    return 0;
}
